  1→import { useEffect, useRef, useState } from "react"
  2→import { useAuth } from "../../Context/useAuth";
  3→import { MoonLoader } from "react-spinners";
  4→import { addReply, getPostReplies } from "../../../API/Api";
  5→import { useInfiniteQuery, useQueryClient } from "@tanstack/react-query";
  6→import { handleClickProfile } from "../../../helpers/handleClicks";
  7→import { useNavigate } from "react-router-dom";
  8→import { motion, AnimatePresence } from "framer-motion";
  9→import VerifiedBadge from "../Badge/VerifiedBadge";
 10→import formatPostDate from "../../../helpers/formatDateString";
 11→
 12→const incrementReplyCount = (old, parentId) => {
 13→    if (!old || !Array.isArray(old.pages)) return old;
 14→
 15→    return {
 16→        ...old,
 17→        pages: old.pages.map((page) => ({
 18→            ...page,
 19→            comments: Array.isArray(page?.comments)
 20→                ? page.comments.map((comment) => {
 21→                    if (comment?.id !== parentId) return comment;
 22→                    return {
 23→                        ...comment,
 24→                        reply_count: (comment?.reply_count || 0) + 1,
 25→                    };
 26→                })
 27→                : page?.comments,
 28→        })),
 29→    };
 30→};
 31→
 32→
 33→const CommentsCards = ({comments, postId}) =>{
 34→    const {user, session} = useAuth();
 35→    const userId = user?.userData[0].id;
 36→    const queryClient = useQueryClient();
 37→
 38→    const [showReplyInput, setShowReplyInput] = useState(false);
 39→    const [showReplies, setShowReplies] = useState(false);
 40→
 41→    const [reply, setReply] = useState('')
 42→    const [replyLoaderId, setReplyLoaderId] = useState('');
 43→
 44→    const navigate = useNavigate();
 45→    const replyInputRef = useRef(null);
 46→
 47→    const clickProfile = handleClickProfile(navigate);
 48→
 49→    const {data, isLoading, fetchNextPage, hasNextPage, isFetchinNextPage} = useInfiniteQuery({
 50→        queryKey: ['getPostReplies', comments.id],
 51→        queryFn: ({pageParam = null, queryKey}) => getPostReplies(queryKey[1], 5, pageParam),
 52→        getNextPageParam: (lastPage) => {
 53→            if(lastPage.hasMore){
 54→                const lastReply = lastPage?.data[lastPage?.data.length - 1];
 55→                return lastReply.id;
 56→            } else{
 57→                return undefined
 58→            }
 59→        },
 60→        refetchOnWindowFocus: false,
 61→        enabled: showReplies,
 62→        staleTime: 1000 * 60 * 5
 63→    })
 64→
 65→    const handleClickReplyButton = (e) =>{
 66→        e.stopPropagation();
 67→        setShowReplyInput(!showReplyInput);
 68→    }
 69→
 70→    const handleShowMoreReplies = () => {
 71→        if(!isFetchinNextPage){
 72→            fetchNextPage();
 73→        }
 74→    }
 75→
 76→    const submitReply = async(parent_id, receiver_id) => {
 77→        const trimmedReply = reply.trim();
 78→        if (!trimmedReply) return;
 79→
 80→        setReplyLoaderId(parent_id)
 81→        queryClient.cancelQueries({ queryKey: ['getPostReplies', parent_id] });
 82→        queryClient.cancelQueries({ queryKey: ['postComments', postId] });
 83→
 84→        const previousReplies = queryClient.getQueryData(['getPostReplies', parent_id]);
 85→        const previousComments = queryClient.getQueryData(['postComments', postId]);
 86→
 87→        const optimisticReply = {
 88→            id: `optimistic-reply-${Date.now()}`,
 89→            post_id: postId,
 90→            parent_id: parent_id,
 91→            comment: trimmedReply,
 92→            created_at: new Date().toISOString(),
 93→            user_id: user?.userData?.[0]?.id,
 94→            users: {
 95→                id: user?.userData?.[0]?.id,
 96→                name: user?.userData?.[0]?.name,
 97→                image_url: user?.userData?.[0]?.image_url,
 98→                badge: user?.userData?.[0]?.badge,
 99→            },
100→            reply_count: 0,
101→        };
102→
103→        queryClient.setQueryData(['getPostReplies', parent_id], (old) => {
104→            if (!old || !Array.isArray(old.pages)) {
105→                return {
106→                    pageParams: [null],
107→                    pages: [{ data: [optimisticReply], hasMore: false }],
108→                };
109→            }
110→
111→            return {
112→                ...old,
113→                pages: old.pages.map((page, index) =>
114→                    index === 0
115→                        ? { ...page, data: [optimisticReply, ...(page?.data || [])] }
116→                        : page
117→                ),
118→            };
119→        });
120→        queryClient.setQueryData(['postComments', postId], (old) => incrementReplyCount(old, parent_id));
121→
122→        try {
123→            const formdata = new FormData();
124→            formdata.append('reply', trimmedReply);
125→
126→            const message = await addReply(userId, postId, parent_id, formdata, receiver_id, session?.access_token);
127→            if(message){
128→                console.log(message);
129→            }
130→            queryClient.invalidateQueries({ queryKey: ['getPostReplies', parent_id] });
131→            queryClient.invalidateQueries({ queryKey: ['postComments', postId] });
132→            setReply('')
133→            setShowReplies(true)
134→        } catch (error) {
135→            queryClient.setQueryData(['getPostReplies', parent_id], previousReplies);
136→            queryClient.setQueryData(['postComments', postId], previousComments);
137→            setReply('')
138→            throw new Error('error adding replies')
139→        } finally {
140→            setReplyLoaderId('')
141→            setShowReplyInput(false);
142→        }
143→    }
144→
145→    useEffect(() =>{
146→        if(showReplyInput && replyInputRef.current){
147→            const timer = setTimeout(() => {
148→                replyInputRef.current.focus();
149→                replyInputRef.current.scrollIntoView({behavior: 'smooth', block: 'center'})
150→            }, 50);
151→
152→            return () => {
153→                clearTimeout(timer)
154→            }
155→        }
156→    }, [showReplyInput])
157→
158→    const replies = data?.pages.flatMap((page) => page.data) || [];
159→
160→    return(
161→        <div style={{marginLeft: comments?.parent_id ? 20 : 0}} className="cm-card">
162→            {comments?.parent_id && <div className="cm-thread-line" />}
163→
164→            <div className="cm-card-content">
165→                <div className="cm-user-row">
166→                    <div
167→                        onClick={(e) => clickProfile(e, user?.userData[0].id, comments?.user_id)}
168→                        className={`cm-avatar-container ${comments?.users?.badge === 'legend' ? 'cm-ring-legend' : comments?.users?.badge === 'og' ? 'cm-ring-og' : ''}`}
169→                    >
170→                        <img className="cm-avatar" src={comments?.users?.image_url || '/assets/profile.jpg'} alt={`${comments?.users?.name || "User"} profile picture`} />
171→                    </div>
172→                    <span
173→                        onClick={(e) => clickProfile(e, user?.userData[0].id, comments?.user_id)}
174→                        className="cm-username"
175→                    >
176→                        {comments?.users?.name}
177→                    </span>
178→                    <VerifiedBadge badge={comments?.users?.badge} size={14} />
179→                    <span className="cm-dot">&middot;</span>
180→                    <span className="cm-date">{formatPostDate(comments?.created_at)}</span>
181→                </div>
182→
183→                <p className="cm-body">{comments?.comment}</p>
184→
185→                <div className="cm-card-actions">
186→                    <button onClick={(e) => handleClickReplyButton(e)} className="cm-reply-btn">
187→                        <svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
188→                            <polyline points="9 17 4 12 9 7" />
189→                            <path d="M20 18v-2a4 4 0 0 0-4-4H4" />
190→                        </svg>
191→                        Reply
192→                    </button>
193→
194→                    {comments?.reply_count > 0 && (
195→                        <button onClick={() => setShowReplies(!showReplies)} className="cm-toggle-replies-btn">
196→                            <svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
197→                                <path d="M21 15a2 2 0 0 1-2 2H7l-4 4V5a2 2 0 0 1 2-2h14a2 2 0 0 1 2 2z" />
198→                            </svg>
199→                            {showReplies ? 'Hide' : 'Show'} {comments?.reply_count} {comments?.reply_count === 1 ? 'reply' : 'replies'}
200→                        </button>
201→                    )}
202→                </div>
203→
204→                {replyLoaderId === comments.id && (
205→                    <div className="cm-reply-loading">
206→                        <MoonLoader size={16} color="var(--loader-color)" speedMultiplier={0.8}/>
207→                    </div>
208→                )}
209→
210→                <AnimatePresence>
211→                    {showReplyInput && (
212→                        <motion.div
213→                            initial={{ height: 0, opacity: 0 }}
214→                            animate={{ height: "auto", opacity: 1 }}
215→                            exit={{ height: 0, opacity: 0 }}
216→                            transition={{ duration: 0.2 }}
217→                            className="cm-reply-input-wrapper"
218→                        >
219→                            <textarea
220→                                ref={replyInputRef}
221→                                maxLength={200}
222→                                value={reply}
223→                                onChange={(e) => setReply(e.target.value)}
224→                                className="cm-reply-textarea"
225→                                placeholder={`Replying to ${comments?.users?.name}...`}
226→                                rows={1}
227→                            />
228→                            <div className="cm-reply-action-row">
229→                                <span className={`cm-reply-char-count ${reply.length > 199 ? 'cm-char-limit' : ''}`}>
230→                                    {reply.length}/200
231→                                </span>
232→                                <button
233→                                    onClick={() => submitReply(comments?.id, comments?.users?.id)}
234→                                    className="cm-reply-submit-btn"
235→                                    disabled={!reply.trim()}
236→                                >
237→                                    Submit
238→                                </button>
239→                            </div>
240→                        </motion.div>
241→                    )}
242→                </AnimatePresence>
243→
244→                <AnimatePresence>
245→                    {showReplies && (
246→                        <motion.div
247→                            initial={{ opacity: 0 }}
248→                            animate={{ opacity: 1 }}
249→                            exit={{ opacity: 0 }}
250→                            transition={{ duration: 0.2 }}
251→                            className="cm-replies-thread"
252→                        >
253→                            {replies?.map((r) => (
254→                                <CommentsCards postId={postId} key={r.id} comments={r}/>
255→                            ))}
256→
257→                            {hasNextPage && (
258→                                <button onClick={handleShowMoreReplies} className="cm-show-more-replies">
259→                                    {isFetchinNextPage ? 'Loading...' : 'Show more replies'}
260→                                </button>
261→                            )}
262→                        </motion.div>
263→                    )}
264→                </AnimatePresence>
265→            </div>
266→        </div>
267→    )
268→}
269→
270→export default CommentsCards;
