 30→    const {session, user, openAuthModal} = useAuth();
 31→    const location = useLocation();
 32→    const outletContext = useOutletContext() || {};
 33→    const { clickOpenSidebar, handleOpenTextEditor } = outletContext;
 34→
 35→    const navigate = useNavigate();
 36→    const modalRef = useRef(null);
 37→    const searchShellRef = useRef(null);
 38→    const timeOutRef = useRef();
 39→    const {ref, inView} = useInView({
 40→        threshold: 0,
 41→        rootMargin: '800px'
 42→    })
 43→    const [postIdSettings, setPostIdSettings] = useState('');
 44→    const [showHeaders, setShowHeaders] = useState(true);
 45→
 46→    const [bookmarkedMessage, setBookmarkedMessage] = useState('');
 47→    const [showBookmarkedMessage, setShowBookmarkedMessage] = useState(null);
 48→    const [searchInput, setSearchInput] = useState('');
 49→    const [debouncedSearchInput, setDebouncedSearchInput] = useState('');
 50→    const [committedSearchQuery, setCommittedSearchQuery] = useState('');
 51→    const [isSearchFocused, setIsSearchFocused] = useState(false);
 52→    const [searchType, setSearchType] = useState('posts');
 53→    const [repostModalJournal, setRepostModalJournal] = useState(null);
 54→    const [repostToastMessage, setRepostToastMessage] = useState('');
 55→
 56→    const handleClickUserProfileOriginal = handleClickProfile(navigate);
 57→    const clickContent = handleCLickContent(navigate);
 58→
 59→    const mutateViews = useAddViewsMutation(session)
 60→
 61→    const handleClickUserProfile = (e, loggedInUserId, clickedUserId, clickedUsername = null) => {
 62→        e.stopPropagation();
