 64→            return openAuthModal();
 65→        }
 66→        handleClickUserProfileOriginal(e, loggedInUserId, clickedUserId, clickedUsername);
 67→    }
 68→
 69→    const viewContent = (e, jsonbContent,wholeText, title, userId, name, avatar, created_at, journalId, isLiked, commentsCount, isBookmarked, likesCount, bookmarksCount, badge, postType = null, canvasDoc = null, userReaction = null, reactionCount = 0) =>{
 70→        e.stopPropagation();
 71→        if(session){
 72→            const formadata = new FormData();
